head.script:
//전역변수
scwin.memJson = $c.data.getMemInfo(); // 로그인 정보를 가져온다.

scwin.sDate = $c.date.getServerDateTime("");  // 서버를 기준으로 현재 날짜 반환
scwin.curDate = scwin.sDate;
scwin.strDate = scwin.sDate.substring(0, 6) + "01";

scwin.txt_eqClssNm = "";
scwin.txt_eqKndNm = "";

scwin.onpageload = function() {
	const codeOptions = [ 
        { grpCd : "ZZ205", compID : "lc_homeClsCd",opt :{"range" : "1,EQ"} },     // 정비소속구분(사업부문)
        { grpCd : "EQ012", compID : "lc_selfOutordClsCd"},                         // 자가/외주
        { grpCd : "EQ010", compID : "lc_fixKndCd, gr_work_pl:fixKndCd" },           // 정비종류
        { grpCd : "ZZ202", compID : "lc_eqClssCd",opt :{"range" : "2,DS"} },       // 장비분류
        { grpCd : "ZZ210", compID : "acb_eqKndCd"},                                // 장비분류
        { grpCd : "EQ905", compID : "lc_fixWrkStsCd, gr_work_pl:fixWrkStsCd"},  // 상태     
    ];
    $c.data.setCommonCode(codeOptions);
};

//-------------------------------------------------------------------------
// UDC 로딩 완료 후
//-------------------------------------------------------------------------
scwin.onUdcCompleted = function() {
    ed_wrkStDt.setValue(scwin.strDate);
    ed_wrkEndDt.setValue(scwin.curDate);
};

scwin.ondataload = async function() {
    for(let i = 0; i < dlt_commonCodeEQ010.getRowCount(); i++){
        dlt_commonCodeEQ010.setCellData(i,"cdNm", "["+ dlt_commonCodeEQ010.getCellData(i, "cd")+"]"+dlt_commonCodeEQ010.getCellData(i, "cdNm"));

        dlt_commonCodeEQ905.setCellData(i,"cdNm", "["+ dlt_commonCodeEQ905.getCellData(i, "cd")+"]"+dlt_commonCodeEQ905.getCellData(i, "cdNm"));
    }
    lc_homeClsCd.setValue(scwin.memJson.eqHomeClsCd);

    if(scwin.memJson.eqHomeClsCd == "null") {
        lc_homeClsCd.setSelectedIndex(0);
    }

    sbm_ds_lux_wrkPlCd.action = "/cm.zz.RetrieveComboCMD.do?sysCd=PsCommonEBC&queryId=retriveWrkplList&param1="+lc_homeClsCd.getValue();
    await $c.sbm.execute(sbm_ds_lux_wrkPlCd);

    $c.gus.cfDisableBtn([btn_Add]); //상세버튼

	lc_wrkPlCd.focus();
}

//-------------------------------------------------------------------------
// 조회
//-------------------------------------------------------------------------
scwin.f_Retrieve = async function() {
    let ret = await $c.gus.cfValidate([tb_wrk]);

    if(!ret) return;

    if (!$c.gus.cfIsAfterDate(ed_wrkStDt.getValue(), ed_wrkEndDt.getValue())) {
        await $c.win.alert(MSG_CM_ERR_039); // 시작일자를 종료일 이전으로 선택[입력]하여 주십시오.
        ed_wrkStDt.Focus();
        return;
    }

    let strPath = "/ps.eq.fixwrkmgnt.fixwrkmgnt.RetrieveFixWorkListCMD.do";

    sbm_retrieve.action = strPath;
    let e = await $c.sbm.execute(sbm_retrieve);
    scwin.sbm_retrieve_submitdone(e);

    if( ds_fix_work_list.getRowCount() > 0 )
        $c.gus.cfDisableBtn();
    else
        $c.gus.cfDisableBtn([btn_Add]); //상세버튼
}

//-------------------------------------------------------------------------
// 신규
//-------------------------------------------------------------------------
scwin.f_Create = async function() {

//팝업화면에게 KEY 정보를 넘겨준다.
let argObject = {
    fixWrkPlCd: lc_wrkPlCd.getValue(),
    homeClsCd: lc_homeClsCd.getValue(),
    fixKndCd: lc_fixKndCd.getValue(),
    selfOutordClsCd: lc_selfOutordClsCd.getValue(), 
    vehclNo: ed_vehclNo.getValue(),
    eqCd: ed_eqCd.getValue(), 
    eqClssCd: lc_eqClssCd.getValue(),
};


let opts  = {
    id : "popup"
    , title : "작업결과등록"
    , popupName : "작업결과등록"  
    , modal : true 
    , type : "browserPopup"
    , width : "1460px"
    , height : "850x"
    , scroll : "yes"
    , resizable : "yes"
    , status : "no"
}

    let url = "/ui/ps/eq/fixwrkmgnt/fixwrkmgnt/eq_330_01_04b.xml";
    let returnValue = await $c.win.openPopup(url, opts, argObject);

    if(returnValue != null && returnValue != "") {
        // 다시 조회함
        scwin.f_Retrieve();
    }
}

//-------------------------------------------------------------------------
// 수정 및 상세
//-------------------------------------------------------------------------
scwin.f_Detail = async function(row) {

    //팝업화면에게 KEY 정보를 넘겨준다.
    let argObject = {
        fixWrkPlCd: ds_fix_work_list.getCellData(row, "fixWrkPlCd"),
        homeClsCd: lc_homeClsCd.getValue(),
        fixWrkNo: ds_fix_work_list.getCellData(row, "fixWrkNo"),
    };

    let opts  = {
        id : "popeq3300104p"
        , title : "작업결과등록"
        , popupName : "작업결과등록"  
        , modal : true 
        , type : "browserPopup"
        , width : "1450px"
        , height : "960x"
        , scroll : "yes"
        , resizable : "yes"
        , status : "no" 
    }

    let url = "/ui/ps/eq/fixwrkmgnt/fixwrkmgnt/eq_330_01_04b.xml";

    let returnValue = await $c.win.openPopup(url, opts, argObject);

    if( returnValue == "REFRESH" ) {
    // 다시 조회함
    scwin.f_Retrieve();
    }
}

//-------------------------------------------------------------------------
// 공통 Popup 처리 : Gubun Code 에 따른 공통 Popup 을 호출한다.
//-------------------------------------------------------------------------
scwin.f_openCommonPopUp = function(disGubun, pCode, pName, pClose, pAllSearch) {
    // 선언부
    let rtnList;  // 공통POP-UP -> 요청화면
    let pWhere = "";

    switch (disGubun)
    {
        case 1:
            // 장비 팝업
            rtnList = udc_eqBasicListInfo.cfCommonPopUp(scwin.udc_eqBasicListInfo_callBackFunc   // XML상의 SELECT ID / 작업장 조회
                                ,pCode                      // 화면에서의 Code Element의 Value
                                ,pName                      // 화면에서의 Name Element의 Value
                                ,pClose                     // 결과가 1건 일때  원도우를  AutoClose 여부  (T:Close,F:Opened)
                                ,null                       // 검색 결과  컬럼의 보여주는 개수 (SELECT절의 순서) MAX:10 - default (2)
                                ,null                       // Title순서
                                ,null                       // 보여주는 각 컬럼들의 폭
                                ,null                       // 컬럼중에서 숨기는 컬럼 지정
                                ,lc_homeClsCd.getValue()        // SQL절의 WHERE절에 원하는 조건을 선택함 MAX:8개까지 가능
                                ,null                       // POP-UP뛰을때 원도우의 사용자 정의 폭
                                ,null                       // POP-UP뛰을때 우도우의 사용자 정의 높이
                                ,null                       // 윈도우 위치 Y좌표
                                ,null                       // 윈도우 위치 X좌표
                                ,null                       // 중복체크여부 ("F")
                                ,pAllSearch                 // 전체검색허용여부 ("F")
                                ,"장비,장비코드,차량번호"   // POP-UP Window Title 검색어1,2 ("Win타이틀,첫번검색Nm,두번검색Nm")
                                );
            break;

        case 2:			
            // 귀속부서 팝업			
            rtnList = udc_acctDeptCdInfo.cfCommonPopUp(scwin.udc_acctDeptCdInfo_callBackFunc 	// XML상의 SELECT ID	
                                    ,ed_acctDeptCd.getValue().trim()      // 화면에서의 Code Element의	Value
                                    ,ed_acctDeptNm.getValue() 		    // 화면에서의 Name Element의	Value
                                    ,pClose					  // 결과가 1건 일때  원도우를	AutoClose 여부	(T:Close,F:Opened)                                    
                                    ,null					  // 검색 결과	컬럼의 보여주는	개수 (SELECT절의 순서) MAX:10 - default (2)
                                    ,null					  // Title순서	
                                    ,null					  // 보여주는 각 컬럼들의 폭	
                                    ,null					  // 컬럼중에서 숨기는	컬럼 지정	
                                    ,pWhere					  // SQL절의 WHERE절에	원하는 조건을 선택함 MAX:8개까지 가능
                                    ,null					  // POP-UP뛰을때 원도우의	사용자 정의	폭
                                    ,null					  // POP-UP뛰을때 우도우의	사용자 정의	높이	
                                    ,null					  // 윈도우 위치 Y좌표	
                                    ,null					  // 윈도우 위치 X좌표
                                    ,null					  // 중복체크여부	("F")
                                    ,pAllSearch				  // 전체검색허용여부	("F")
                                    ,"귀속부서,부서코드,부서명"	  // POP-UP Window Title 검색어1,2 ("Win타이틀,첫번검색Nm,두번검색Nm")
                                    );
            break;
    }	
}

scwin.udc_eqBasicListInfo_callBackFunc = function (rtnList) {
    if (rtnList != null && rtnList[0] != 'N/A') {
        									  //장비코드  차량번호
  	$c.gus.cfSetReturnValue(rtnList, ed_eqCd,ed_vehclNo);
    } else {
        ed_eqCd.setValue("");
        ed_vehclNo.setValue("");
    } 
}

scwin.udc_acctDeptCdInfo_callBackFunc = function (rtnList) {
    if (rtnList != null && rtnList[0] != 'N/A') {
                                        //귀속부서코드		부서명
        $c.gus.cfSetReturnValue(rtnList, ed_acctDeptCd,   ed_acctDeptNm);
    } else {
        ed_acctDeptCd.setValue("");
        ed_acctDeptNm.setValue("");
    } 
}

//-------------------------------------------------------------------------
// 팝업 처리시 검색된 데이터인 경우 팝업 처리 안함.
//-------------------------------------------------------------------------
scwin.f_chkOpenCommonPopUp = function(inObj, pairObj, disGubun, isCode) {
    // 값이 입력이 안된 경우, 해당 Text Box가 readonly 인 경우, 이전값과 동일한 경우 팝업을 실행하지 않음.
    if (!$c.gus.cfCanOpenPopup(inObj, pairObj))
        return;

    // 짝이 되는 오브젝트의 값 제거
    $c.gus.cfClearPairObj(pairObj);

    // 검색어 세팅
    let pVal = $c.gus.cfGetValue(inObj);

    // inObj가 코드 필드일 경우 팝업
    if (isCode == null || isCode == true)
        scwin.f_openCommonPopUp(disGubun, pVal, '', 'T', 'F');
    // inObj가 코드명 필드일 경우 팝업
    else
        scwin.f_openCommonPopUp(disGubun, '', pVal, 'T', 'F');
}

//-------------------------------------------------------------------------
// 조회 조건 지우기
//-------------------------------------------------------------------------
scwin.f_FieldClear = function()  {
    $c.gus.cfInitObjects(tb_wrk, null);
    scwin.lc_homeClsCd_onviewchange();
}

scwin.udc_eqBasicListInfo_onviewchangeNameEvent = function (info) {
    scwin.f_chkOpenCommonPopUp(ed_vehclNo, ed_eqCd,1,false);
};

scwin.udc_eqBasicListInfo_onclickEvent = function (e) {
    scwin.f_openCommonPopUp(1, ed_eqCd.getValue(), ed_vehclNo.getValue(),'F','T');
};

scwin.udc_acctDeptCdInfo_onclickEvent = function (e) {
    scwin.f_openCommonPopUp(2, ed_acctDeptCd.getValue(), ed_acctDeptNm.getValue(),'F','T');
};

scwin.udc_acctDeptCdInfo_onviewchangeNameEvent = function (info) {
    scwin.f_chkOpenCommonPopUp(ed_acctDeptNm, ed_acctDeptCd, 2, false);
};

scwin.btn_clear_onclick = function (e) {
    scwin.f_FieldClear();
};

scwin.btn_retrieve_onclick = function (e) {
    scwin.f_Retrieve();
};


//-------------------------------------------------------------------------
// 엑셀 Download
//-------------------------------------------------------------------------
scwin.f_runExcel = async function() {
    let sheetTitle = "작업결과목록현황";

    const options = {
        fileName: sheetTitle + ".xlsx",
        sheetName: sheetTitle
    };
    $c.data.downloadGridViewExcel(gr_work_pl, options);  
};
scwin.btn_Init_onclick = function (e) {
    scwin.f_Create();
};

scwin.btn_Add_onclick = function (e) {
    scwin.f_Detail(ds_fix_work_list.getRowPosition());
};

scwin.sbm_retrieve_submitdone = async function (e) {
    if( ds_fix_work_list.getRowCount() == 0 ) {
        await $c.win.alert("조회된 데이터가 없습니다.");
        return;
    }

    let options = {};
    options.sortIndex = "wrkIntendDt fixWrkNo ";
    options.sortOrder = "-1 1";

    ds_fix_work_list.multisort( options );
    gr_work_pl.setFocusedCell(0, "fixWrkNo");

    totalRows.setValue(ds_fix_work_list.getRowCount());
};

scwin.gr_work_pl_oncellclick = function (rowIndex, columnIndex, columnId) {
    if( rowIndex >= 0 ) {
		if( columnId =="fixWrkNo" ) scwin.f_Detail(rowIndex);
	}
};

scwin.lc_homeClsCd_onviewchange = async function (info) {
    sbm_ds_lux_wrkPlCd.action = "/cm.zz.RetrieveComboCMD.do?sysCd=PsCommonEBC&queryId=retriveWrkplList&param1="+lc_homeClsCd.getValue();
    await $c.sbm.execute(sbm_ds_lux_wrkPlCd);

    lc_wrkPlCd.setValue(scwin.memJson.fixWrkPlCd);

    if(lc_wrkPlCd.getSelectedIndex() == -1) {
        lc_wrkPlCd.setSelectedIndex(0);
    }
};

scwin.udc_eqBasicListInfo_onblurCodeEvent = function (e) {
    scwin.f_chkOpenCommonPopUp(ed_eqCd, ed_vehclNo,1,true);
};

scwin.udc_acctDeptCdInfo_onblurCodeEvent = function (e) {
    scwin.f_chkOpenCommonPopUp(ed_acctDeptCd, ed_acctDeptNm, 2, false);
};
